import { useState, useEffect, useCallback } from 'react';
import ApiService from '../Services/api';

const useChat = () => {
  const [messages, setMessages] = useState([]);
  const [inputMessage, setInputMessage] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isTyping, setIsTyping] = useState(false);
  const [sessionId, setSessionId] = useState(null);

  useEffect(() => {
    initializeChat();
  }, []);

  const initializeChat = async () => {
    try {
      const session = await ApiService.createNewSession();
      setSessionId(session.session_id);
      
      // Professional welcome message
      setMessages([{
        id: 'welcome',
        type: 'bot',
        content: "Hello! I'm Nexus, your AI assistant. How can I help you today?",
        timestamp: new Date(),
        subject_area: 'general'
      }]);
    } catch (error) {
      console.error('Failed to initialize chat:', error);
      // Fallback welcome message
      setMessages([{
        id: 'welcome-fallback',
        type: 'bot',
        content: "Welcome to Nexus! I'm here to help you with your questions.",
        timestamp: new Date(),
        subject_area: 'general'
      }]);
    }
  };

  const sendMessage = useCallback(async (uploadedFile = null) => {
    if (!inputMessage.trim() && !uploadedFile) return;

    // If uploading a file, create a message for it
    if (uploadedFile) {
      const fileMessage = {
        id: `file-${Date.now()}`,
        type: 'user',
        content: `Uploaded file: ${uploadedFile.filename}`,
        fileInfo: uploadedFile,
        timestamp: new Date()
      };
      setMessages(prev => [...prev, fileMessage]);
    }

    const userMessage = {
      id: `user-${Date.now()}`,
      type: 'user',
      content: inputMessage,
      timestamp: new Date()
    };

    setMessages(prev => [...prev, userMessage]);
    const currentMessage = inputMessage;
    setInputMessage('');
    setIsLoading(true);
    setIsTyping(true);

    try {
      const payload = {
        message: currentMessage,
        session_id: sessionId
      };

      // Handle file content from uploaded files
      if (uploadedFile && uploadedFile.content) {
        if (uploadedFile.content.text_content) {
          payload.file_content = uploadedFile.content.text_content;
        } else if (uploadedFile.content.summary) {
          payload.file_content = uploadedFile.content.summary;
        } else {
          payload.file_content = JSON.stringify(uploadedFile.content);
        }
      }

      const response = await ApiService.sendMessage(payload.message, sessionId, payload.file_content);
      
      // Reduced typing delay for better responsiveness
      setTimeout(() => {
        const botMessage = {
          id: `bot-${Date.now()}`,
          type: 'bot',
          content: response.response || response.error || "I couldn't process that request.",
          timestamp: new Date(),
          detected_language: response.detected_language,
          subject_area: response.subject_area || 'general'
        };

        setMessages(prev => [...prev, botMessage]);
        setIsLoading(false);
        setIsTyping(false);
      }, 800); // Reduced from 1000ms

    } catch (error) {
      console.error('Chat error:', error);
      
      const errorMessage = {
        id: `error-${Date.now()}`,
        type: 'bot',
        content: "Sorry, I encountered an error. Please try again.",
        timestamp: new Date(),
        subject_area: 'general'
      };
      
      setMessages(prev => [...prev, errorMessage]);
      setIsLoading(false);
      setIsTyping(false);
    }
  }, [inputMessage, sessionId]);

  const clearChat = useCallback(async () => {
    try {
      if (sessionId) {
        await ApiService.clearSession(sessionId);
      }
      
      // Professional clear message
      setMessages([{
        id: `cleared-${Date.now()}`,
        type: 'bot',
        content: "Chat cleared. How can I help you?",
        timestamp: new Date(),
        subject_area: 'general'
      }]);
      
      // Create new session
      const session = await ApiService.createNewSession();
      setSessionId(session.session_id);
      
    } catch (error) {
      console.error('Failed to clear chat:', error);
      
      // Fallback clear
      setMessages([{
        id: `cleared-fallback-${Date.now()}`,
        type: 'bot',
        content: "Chat cleared. Ready for your next question.",
        timestamp: new Date(),
        subject_area: 'general'
      }]);
    }
  }, [sessionId]);

  const getMessageCount = useCallback(() => {
    return messages.filter(msg => msg.type === 'user').length;
  }, [messages]);

  const getLastBotMessage = useCallback(() => {
    const botMessages = messages.filter(msg => msg.type === 'bot');
    return botMessages[botMessages.length - 1];
  }, [messages]);

  return {
    messages,
    inputMessage,
    setInputMessage,
    isLoading,
    isTyping,
    sessionId,
    sendMessage,
    clearChat,
    getMessageCount,
    getLastBotMessage
  };
};

export default useChat;
